import{c as t,Q as a,j as r,m as i}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"AI Harness Engineering: A Runtime Substrate for Foundation-Model Software Agents","description":"","frontmatter":{"title":"AI Harness Engineering: A Runtime Substrate for Foundation-Model Software Agents","authors":"Hailin Zhong, Shengxin Zhu","published":"2026-05-13T00:00:00.000Z","source":"https://arxiv.org/abs/2605.13357"},"headers":[],"relativePath":"research/agent-harness/references/2026-05-13-ai-harness-engineering-runtime-substrate-2605-13357.md","filePath":"research/agent-harness/references/2026-05-13-ai-harness-engineering-runtime-substrate-2605-13357.md","lastUpdated":1779901665000}'),n={name:"research/agent-harness/references/2026-05-13-ai-harness-engineering-runtime-substrate-2605-13357.md"};function o(s,e,d,l,c,u){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="ai-harness-engineering-a-runtime-substrate-for-foundation-model-software-agents" tabindex="-1">AI Harness Engineering: A Runtime Substrate for Foundation-Model Software Agents <a class="header-anchor" href="#ai-harness-engineering-a-runtime-substrate-for-foundation-model-software-agents" aria-label="Permalink to &quot;AI Harness Engineering: A Runtime Substrate for Foundation-Model Software Agents&quot;">​</a></h1><p><strong>Authors</strong>: Hailin Zhong, Shengxin Zhu <strong>Published</strong>: May 13, 2026 <strong>Source</strong>: <a href="https://arxiv.org/abs/2605.13357" target="_blank" rel="noreferrer">https://arxiv.org/abs/2605.13357</a><strong>arXiv ID</strong>: 2605.13357 <strong>Categories</strong>: cs.SE, cs.AI</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>Autonomous software-engineering capability is an emergent property of a <strong>model–harness–environment system</strong>, not of the model alone. The authors argue that agent failures are not primarily caused by insufficient model capability but by missing runtime infrastructure. They propose AI Harness Engineering—a runtime substrate framework defining eleven component responsibilities, an H0–H3 evaluation ladder, and a trace-based evaluation protocol producing auditable &quot;episode packages.&quot;</p><hr><h2 id="core-thesis" tabindex="-1">Core Thesis <a class="header-anchor" href="#core-thesis" aria-label="Permalink to &quot;Core Thesis&quot;">​</a></h2><p>Rather than attributing agent failures to models, the gap lies in missing <strong>runtime infrastructure</strong>:</p><blockquote><p>&quot;Autonomous software-engineering capability is an emergent property of a model–harness–environment system, not of the model alone.&quot;</p></blockquote><p>The harness mediates how foundation-model agents observe projects, act on them, receive feedback, and establish completion.</p><hr><h2 id="key-contributions" tabindex="-1">Key Contributions <a class="header-anchor" href="#key-contributions" aria-label="Permalink to &quot;Key Contributions&quot;">​</a></h2><h3 id="_1-eleven-component-responsibilities" tabindex="-1">1. Eleven Component Responsibilities <a class="header-anchor" href="#_1-eleven-component-responsibilities" aria-label="Permalink to &quot;1. Eleven Component Responsibilities&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Component</th><th>Runtime Contract</th><th>Failure Mode</th><th>Evidence</th></tr></thead><tbody><tr><td>Task interface</td><td>Present objective and success criteria</td><td>Underspecified goals</td><td>Task record</td></tr><tr><td>Context manager</td><td>Select task-relevant content</td><td>Wrong-file inspection</td><td>Context trace</td></tr><tr><td>Tool registry</td><td>Declare available tools</td><td>Failed calls; unsafe commands</td><td>Tool trace</td></tr><tr><td>Project memory</td><td>Provide architecture, testing knowledge</td><td>Repeated rediscovery</td><td>Memory references</td></tr><tr><td>Task state</td><td>Maintain hypothesis and progress</td><td>Execution drift</td><td>Task-state file</td></tr><tr><td>Observability layer</td><td>Expose logs and runtime errors</td><td>Unverifiable success</td><td>Observation log</td></tr><tr><td>Failure attribution</td><td>Separate observation from diagnosis</td><td>Random patching</td><td>Attribution log</td></tr><tr><td>Verification protocol</td><td>Map requirements to evidence</td><td>Unverified success</td><td>Verification trace</td></tr><tr><td>Permission boundary</td><td>Restrict risky actions</td><td>Unsafe edits</td><td>Permission record</td></tr><tr><td>Entropy auditor</td><td>Detect maintenance burden</td><td>Stale docs; residue</td><td>Entropy audit</td></tr><tr><td>Intervention logger</td><td>Record human assistance</td><td>Invisible scaffolding</td><td>Intervention log</td></tr></tbody></table><p><strong>Five design principles</strong>: explicit resources, traceable mediation, requirement-level verification, attribution-before-recovery, maintenance awareness.</p><h3 id="_2-h0–h3-harness-ladder" tabindex="-1">2. H0–H3 Harness Ladder <a class="header-anchor" href="#_2-h0–h3-harness-ladder" aria-label="Permalink to &quot;2. H0–H3 Harness Ladder&quot;">​</a></h3><p>A controlled-visibility ablation showing runtime support differences:</p><ul><li><strong>H0</strong>: Task + repository files only</li><li><strong>H1</strong>: Plus tool/test registries</li><li><strong>H2</strong>: Plus project memory and task-state tracking</li><li><strong>H3</strong>: Plus deterministic checks, failure attribution, and verification protocols</li></ul><h3 id="_3-trace-based-evaluation-protocol" tabindex="-1">3. Trace-Based Evaluation Protocol <a class="header-anchor" href="#_3-trace-based-evaluation-protocol" aria-label="Permalink to &quot;3. Trace-Based Evaluation Protocol&quot;">​</a></h3><p>Eight trace types recorded per episode: action, tool, context, verification, failure attribution, intervention, entropy audit, and outcome. Produces <strong>episode packages</strong>—auditable records adjudicating episodes not just by task success but by evidence quality.</p><h3 id="_4-five-label-outcome-taxonomy" tabindex="-1">4. Five-Label Outcome Taxonomy <a class="header-anchor" href="#_4-five-label-outcome-taxonomy" aria-label="Permalink to &quot;4. Five-Label Outcome Taxonomy&quot;">​</a></h3><ul><li><code>autonomous_verified_success</code>: requirements met with sufficient evidence, no missing-harness intervention</li><li><code>assisted_verified_success</code>: correct patch but required human assistance</li><li><code>unverified_success</code>: correct behavior without proper evidence structure</li><li><code>failed</code>: behavior or tests fail</li><li><code>unsafe_invalid</code>: tests weakened or unrelated edits occur</li></ul><hr><h2 id="evaluation" tabindex="-1">Evaluation <a class="header-anchor" href="#evaluation" aria-label="Permalink to &quot;Evaluation&quot;">​</a></h2><p><strong>Control task</strong>: login application where empty passwords incorrectly reach credential matching instead of triggering validation rejection.</p><p>All four H-levels produced working patches, but evidence packages differed systematically. <strong>H3</strong> produced bug reproduction logs, failure attribution records, deterministic requirement checks, and structured verification reports—evidence unavailable at lower levels.</p><hr><h2 id="key-metrics" tabindex="-1">Key Metrics <a class="header-anchor" href="#key-metrics" aria-label="Permalink to &quot;Key Metrics&quot;">​</a></h2><p><strong>Missing-Harness Human Intervention Rate (M-HIR)</strong>: Treats human help as diagnostic signal. When a human interprets a test failure → missing observability; when a human verifies final behavior → missing verification support.</p><p><strong>Failure Taxonomy</strong>: Eight failure types: context, tool, feedback, verification, recovery, entropy, model, and unknown.</p><hr><h2 id="implications-for-practice" tabindex="-1">Implications for Practice <a class="header-anchor" href="#implications-for-practice" aria-label="Permalink to &quot;Implications for Practice&quot;">​</a></h2><ol><li><strong>Verification as Runtime Capability</strong>: H3 places verification inside the harness; agents must reproduce failures, attribute them, apply targeted fixes, verify requirements, report limitations.</li><li><strong>Memory Auditability</strong>: Project memory benefits only when agent use is traced via context trace.</li><li><strong>Attribution Before Action</strong>: Diagnosis step between failure observation and patching prevents random fixes.</li><li><strong>Tool Stability as Harness Responsibility</strong>: Recording timeouts, flaky tests, and recovery attempts makes tool instability analyzable.</li><li><strong>Entropy Management</strong>: Tracking maintenance burden (stale docs, unnecessary dependencies, weakened tests) places sustainability inside the autonomous loop.</li></ol><hr><h2 id="broader-vision" tabindex="-1">Broader Vision <a class="header-anchor" href="#broader-vision" aria-label="Permalink to &quot;Broader Vision&quot;">​</a></h2><p>Reframes the central question from &quot;Can a foundation model produce a patch?&quot; to <strong>&quot;Can the model–harness–environment system produce a verifiable, attributed, and maintainable change?&quot;</strong></p><p>Future development environments will need explicit, agent-readable affordances: architecture maps, testing guides, deterministic check registries, task-state files, entropy dashboards, and permission manifests—optimized for machine agents rather than implicit human knowledge.</p>',37)])])}const m=t(n,[["render",o]]);export{g as __pageData,m as default};
